mapper.select:
SELECT er.*, p.title AS product_title, p.cover_img AS product_cover_img, applicant.nickname AS applicant_name, owner.nickname AS owner_name, op.title AS offer_product_title, op.cover_img AS offer_product_cover_img, oc.name AS offer_product_category_name, op.price AS offer_product_price FROM exchange_request er LEFT JOIN product p ON er.product_id = p.id LEFT JOIN sys_user applicant ON er.applicant_id = applicant.id LEFT JOIN sys_user owner ON er.owner_id = owner.id LEFT JOIN product op ON er.offer_product_id = op.id LEFT JOIN product_category oc ON op.category_id = oc.id WHERE 1=1
AND er.applicant_id = #{userId}
AND er.owner_id = #{userId}
AND er.status = #{status}
ORDER BY er.create_time DESC
